class Graph:
    def __init__(self):
        self.adj_list = {}

    # 1. Add Vertex - O(1)
    def add_vertex(self, vertex):
        if vertex not in self.adj_list:
            self.adj_list[vertex] = set()

    # 2. Add Edge - O(1) average
    def add_edge(self, u, v, bidirectional=True):
        self.add_vertex(u)
        self.add_vertex(v)
        self.adj_list[u].add(v)
        if bidirectional:
            self.adj_list[v].add(u)

    # 3. Remove Edge - O(1) average
    def remove_edge(self, u, v, bidirectional=True):
        if u in self.adj_list and v in self.adj_list[u]:
            self.adj_list[u].remove(v)
        if bidirectional and v in self.adj_list and u in self.adj_list[v]:
            self.adj_list[v].remove(u)

    # 4. Remove Vertex - O(V + E) time
    def remove_vertex(self, vertex):
        if vertex in self.adj_list:
            # Remove all incoming edges
            for neighbor in list(self.adj_list[vertex]):
                self.remove_edge(vertex, neighbor)
            # Remove the vertex entry
            del self.adj_list[vertex]

g = Graph()
g.add_edge('A', 'B')
g.add_edge('A', 'C')
print(g.adj_list)      # {'A': {'B', 'C'}, 'B': {'A'}, 'C': {'A'}}
g.remove_edge('A', 'C')
print(g.adj_list)      # {'A': {'B'}, 'B': {'A'}, 'C': set()}
